def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 2.0:
            priority = (ratio - 2.0) ** 3 * 180 + 40
            if capacity % 5 == 0:
                priority += 4.5
            else:
                for x in range(1, 4):
                    priority += ((-1) ** x) * np.cos(ratio * np.pi * x) * 3 * x
            if ratio > 3.5:
                priority += (ratio - 3.5) ** 2 * 150
            if capacity > item * 15:
                for y in range(1, 5):
                    priority -= np.sqrt(y) * (ratio ** (0.5 / y)) * ((-1) ** (y + 1)) * y * 0.25
        elif ratio > 1.0:
            priority = (ratio - 1.0) * 280 + 25
            if capacity % 8 == 0:
                priority += 5.0
            elif capacity % 4 == 0:
                priority += 3.2
            else:
                priority += 1.7
            for k in range(1, 6):
                term = ((-1) ** k) * np.tanh(ratio * k) * 4 / (k + 0.5)
                if k % 2 == 0:
                    term *= 1.5
                priority += term
            if ratio > 1.7:
                priority += (ratio - 1.7) ** 2 * 90
                if capacity % 3 == 0:
                    priority += 2.1
        else:
            accum = 0.0
            for n in range(1, 12):
                coeff = ((-1) ** (n + 1)) * (ratio ** (n * 1.4)) / (n * 1.2)
                if n % 4 == 0:
                    coeff *= 2.0
                accum += coeff
            priority += abs(accum) * 2.1
            if capacity < item * 1.5:
                priority *= 3.2
            log_diff = np.log(capacity + 5) - np.log(item + 2)
            if log_diff > 0:
                priority += 11 / log_diff
            else:
                priority += 40
            if capacity % 9 == 0:
                priority += 1.3
            elif capacity % 6 == 0:
                priority += 0.9
            else:
                priority -= 0.6
            if ratio < 0.3:
                for m in range(1, 7):
                    add = ((-1) ** (m + 1)) * (ratio ** (m * 2.8)) * (m * 0.9)
                    if m == 5 and capacity > item * 6:
                        add *= 1.8
                    priority += add
            if capacity > item * 5:
                priority -= 4.0
            if capacity % 11 == 0 and ratio < 0.45:
                priority -= 1.3
            if capacity > item * 10:
                for p in range(2, 8):
                    sign = (-1) ** (p + 1)
                    power = ratio ** (1 / (p + 0.5))
                    priority += np.log(p + capacity % (p + 1) + 1) * power * sign * p * 0.45
            if priority > 65:
                priority = 65 + np.log(priority - 64) * 1.8
        if priority < 0:
            priority = 0
        priorities[i] = priority
    return priorities
